def make_general_blueprint_array(blueprints,rows=None,cols=None):
	cell_dims =   3,5 #get_station_dimensions(blueprints[-1])
	print(cell_dims)
	total_blueprint = copy.deepcopy(blueprints[0])

	total_blueprint["blueprint"]["entities"] = []
	if rows == None and cols == None:
		rows,cols = [math.ceil(math.sqrt(len(blueprints)))]*2
	entity_number = 1
	print(rows,cols)
	for i in range(rows):
		for j in range(cols):
			
			# print(len(blueprints))
			next_entities = blueprints[0]["blueprint"]["entities"]
			blueprints.pop(0)
			for k,v in enumerate(next_entities):
				v["position"]["x"] += cell_dims[0]*j
				v["position"]["y"] += cell_dims[1]*i
				v["items"] = {"speed-module-2":4}
				v["entity_number"] = entity_number
				entity_number +=1
				total_blueprint["blueprint"]["entities"].append(v)
			if not blueprints:
				return total_blueprint
	return total_blueprint


def make_single_assembler(product ):
	with open("blueprints\\rail_assembling_machine") as f:
		rail_assembler = convertoToJson(f.read())
		ingredients = get_recipe(product)
	# rail_assembler = convertoToJson("")
	entities= rail_assembler["blueprint"]["entities"]
	for i,v in enumerate(entities):
		if v["name"] == "logistic-chest-requester":
			try:
				v["request_filters"] = [ {"index":j+1,"name":ingredient,"count":get_stack_size(ingredient)*48//len(ingredients)} for j,ingredient in enumerate(ingredients) if ingredient not in fluids ]
			except:
				pass
		elif v["name"] == "assembling-machine-3":
			if "plate" in product or product in ["stone"]:
				v["name"] = "electric-furnace"
			elif product in ["sulfur","plastic-bar","sulfuric-acid"]:
				v["name"] = "chemical-plant"
				v["direction"] =4
			elif "nuclear" in product:
				v["name"] = "centrifuge"
			v["recipe"] = product
		entities[i] = v
	rail_assembler["blueprint"]["entities"] = entities
	return rail_assembler


def filter_blueprint_for_item(blueprint,item):
	blueprint_copy = copy.deepcopy(blueprint)
	blueprint_copy["blueprint"]["entities"] = []
	i = 1
	for entity in (blueprint["blueprint"]["entities"]):
		if entity["name"] == item:
			entity["entity_number"] = i
			blueprint_copy["blueprint"]["entities"].append(entity)
			i+=1
	return blueprint

def get_proximity_dictionary_alt_medium(blueprint,number_of_neighbors):
	with open("javascript_blueprint.json","w+") as f:
		f.write(json.dumps((blueprint)))
	os.system(f"node make_proximity_dictionary_medium.js {number_of_neighbors}")
	with open("proximity_dictionary.json") as f:
		return json.loads(f.read())


def neighbourify_medium_electric_poles(blueprint,number_of_neighbors = 3):
	proximity_dictionary = {int(k):v for k,v in get_proximity_dictionary_alt_medium(blueprint,number_of_neighbors).items()}

	for i,v in enumerate(blueprint["blueprint"]["entities"]):
		if v["name"] == "medium-electric-pole":
			v["neighbours"] = proximity_dictionary[i+1]
	return blueprint

def get_station_type(blueprint):
	for i,v in enumerate(blueprint["blueprint"]["entities"]):
		if "train-stop" == v["name"]:
			if "shipping" in v["station"]:
				return v["station"].split(" ")[0]

