def make_train_schedules(blueprint,heirarchy_dictionary):
	letters_and_numbers =  "".join([chr(i) for i in range(ord('A'),ord('Z')+1)])+"".join([chr(i) for i in range(ord('a'),ord('z')+1)])+"".join([str(i) for i in range(10)])
	schedules = []
	coal_stations = []

	for i,v in enumerate(blueprint["blueprint"]["entities"]):
		if v["name"] == "train-stop":
			new_station = "".join([random.choice(letters_and_numbers) for i in range(20)])
			v["station"] = new_station 
			coal_stations.append(new_station)
	for i,v in enumerate(blueprint["blueprint"]["entities"]):
		if v["name"] == "locomotive":
			schedules.append(make_schedule(origin, destination, coal_stations.pop(0), v["entity_number"]))#{"locomotives":[v["entity_number"]], "schedule":[{"station":"".join([random.choice(letters_and_numbers) for i in range(20)])}]})

	blueprint["blueprint"]["schedules"] = schedules
	return blueprint
