def get_number_of_locomotives(blueprint):
	total = 0
	for i,v in enumerate(blueprint["blueprint"]["entities"]):
		total += v["name"] == "locomotive"
	return total

def get_product_recipe_relationships(heirarchy):
	product_ingredient_dictionary=defaultdict(dict)
	def recurse(h,amount = 1):
		print("h",h)

		nonlocal product_ingredient_dictionary
		product = [i for i in h.keys()][0]
		ingredient_dictionary = h[product]
		# print("ingredient_dictionary",json.dumps(ingredient_dictionary,indent=2))

		product_amount = amount*ingredient_dictionary["amount"]
		for ingredient in ingredient_dictionary["ingredients"]:
			#single key value pair dictionary
			new_dictionary = {ingredient: ingredient_dictionary["ingredients"][ingredient]["amount"]*product_amount}
			old_dictionary = product_ingredient_dictionary[product]
			print(old_dictionary)
			new_dictionary.update(old_dictionary)
			product_ingredient_dictionary[product] = new_dictionary
			if ingredient_dictionary["ingredients"][ingredient]["ingredients"] != None:

				recurse(ingredient_dictionary["ingredients"][ingredient],product_amount)
	recurse(heirarchy)
	return product_ingredient_dictionary
